if (!function_exists('sd_t')) {
  function sd_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('sd_h')) {
  function sd_h($key, $fallback = '') { return htmlspecialchars((string) sd_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('sd_js')) {
  function sd_js($key, $fallback = '') { return json_encode(sd_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-01');$defaultTo=date('Y-m-d');
$customers=$db->query("SELECT kode_penerima,nama FROM penerima ORDER BY nama");
$salesOrders=$db->query("SELECT so.id_sales_order,so.no_sales_order,so.so_date,so.currency,p.nama customer_name,COALESCE(SUM(sod.nilai),0) amount FROM sales_order so LEFT JOIN sales_order_detail sod ON sod.id_sales_order=so.id_sales_order LEFT JOIN penerima p ON p.kode_penerima=so.kode_penerima WHERE COALESCE(so.approval_status,'APPROVED') NOT IN ('REJECTED','CANCELLED') GROUP BY so.id_sales_order ORDER BY so.so_date DESC,so.id_sales_order DESC LIMIT 300");
$quotations=$db->query("SELECT sq.id_quotation,sq.no_sales_quotation,sq.tgl,sq.currency,COALESCE(p.nama,sq.customer_name) customer_name,COALESCE(SUM(sqd.nilai),0) amount FROM sales_quotation sq LEFT JOIN sales_quotation_detail sqd ON sqd.id_quotation=sq.id_quotation LEFT JOIN penerima p ON p.kode_penerima=sq.kode_penerima WHERE sq.status NOT IN ('REJECTED','CANCELLED','EXPIRED') GROUP BY sq.id_quotation ORDER BY sq.tgl DESC,sq.id_quotation DESC LIMIT 300");
$kpi=$db->fetch("SELECT COUNT(*) doc_count,COALESCE(SUM(net_amount),0) net_amount,COALESCE(SUM(tax_amount),0) tax_amount,COALESCE(SUM(gross_amount),0) gross_amount FROM sales_invoice WHERE billing_type='PF' AND invoice_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
