, customer"></div><div class="col-lg-3"><button id="btn_filter_pf" class="btn btn-primary"><i class="fa fa-filter"></i> <?=sd_h('common_filter', 'Filter');?></button> <button id="btn_reset_pf" class="btn btn-default"><i class="fa fa-refresh"></i> <?=sd_h('common_reset', 'Reset');?></button> <button id="btn_excel_pf" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=sd_h('common_excel', 'Excel');?></button></div></div></form></div></div>
