  <div id="modal_pf_form" class="modal fade"><div class="modal-dialog modal-lg" style="width:94%"><div class="modal-content"><form id="form_pf" class="form-horizontal" method="post" action="<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=in"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title"><i class="fa fa-file-text-o"></i> Create Proforma Invoice</h4></div><div class="modal-body"><div class="alert alert-danger error_data" style="display:none"><span class="isi_warning"></span></div><div class="pf-section">Source Document</div><div class="form-group"><label class="control-label col-lg-2">Source Type</label><div class="col-lg-3"><select name="reference_type" id="reference_type" class="form-control"><option value="SO"><?=sd_h('sales_order', 'Sales Order');?></option><option value="QUOTATION"><?=sd_h('sales_quotation', 'Sales Quotation');?></option></select></div><label class="control-label col-lg-2"><?=sd_h('sales_order', 'Sales Order');?></label><div class="col-lg-5 pf-ref pf-ref-so"><select name="sales_order_id" id="sales_order_id" class="form-control"><option value=""></option><?php foreach($salesOrders as $so){ ?><option value="<?=(int)$so->id_sales_order;?>"><?=htmlspecialchars($so->no_sales_order.' | '.$so->customer_name.' | '.$so->currency.' '.number_format((float)$so->amount,2,'.',','),ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><div class="col-lg-5 pf-ref pf-ref-quotation" style="display:none"><select name="quotation_id" id="quotation_id" class="form-control"><option value=""></option><?php foreach($quotations as $q){ ?><option value="<?=(int)$q->id_quotation;?>"><?=htmlspecialchars($q->no_sales_quotation.' | '.$q->customer_name.' | '.$q->currency.' '.number_format((float)$q->amount,2,'.',','),ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div></div><div id="source_summary" class="well well-sm" style="display:none"></div><div class="pf-section">Proforma Header</div><div class="form-group"><label class="control-label col-lg-2">Proforma No</label><div class="col-lg-4"><input name="no_sales_invoice" id="no_sales_invoice" class="form-control" readonly></div><label class="control-label col-lg-2"><?=sd_h('sales_date', 'Date');?></label><div class="col-lg-4"><div class="input-group date pf-date"><input name="invoice_date" id="invoice_date" class="form-control" value="<?=date('Y-m-d');?>" required><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div></div><div class="form-group"><label class="control-label col-lg-2">Valid Until</label><div class="col-lg-4"><div class="input-group date pf-date"><input name="proforma_valid_until" id="proforma_valid_until" class="form-control" value="<?=date('Y-m-d',strtotime('+30 days'));?>"><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div><label class="control-label col-lg-2"><?=sd_h('sales_currency', 'Currency');?></label><div class="col-lg-2"><input name="valuta" id="valuta" class="form-control" readonly></div><label class="control-label col-lg-1"><?=sd_h('sales_tax', 'Tax');?></label><div class="col-lg-1"><input id="tax_label" class="form-control" readonly></div></div><div class="row"><div class="col-sm-4"><div class="well well-sm"><span>DPP</span><div class="pf-money" id="net_preview">0.00</div></div></div><div class="col-sm-4"><div class="well well-sm"><span>PPN</span><div class="pf-money" id="tax_preview">0.00</div></div></div><div class="col-sm-4"><div class="well well-sm"><span>Grand Total</span><div class="pf-money" id="gross_preview">0.00</div></div></div></div><div class="pf-section">Notes & Signature</div><div class="form-group"><label class="control-label col-lg-2">Signed By</label><div class="col-lg-4"><input name="ttd" class="form-control" required></div><label class="control-label col-lg-2">Notes</label><div class="col-lg-4"><input name="catatan" class="form-control"></div></div><input type="hidden" name="bill_to" id="bill_to"><input type="hidden" name="ship_to" id="ship_to"><input type="hidden" name="reference_no" id="reference_no"><input type="hidden" name="no_sales_order" id="no_sales_order"><input type="hidden" name="nopo" id="nopo"><input type="hidden" name="tax" id="tax"><input type="hidden" name="net_amount" id="net_amount"><input type="hidden" name="tax_amount" id="tax_amount"><input type="hidden" name="gross_amount" id="gross_amount"></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=sd_h('common_close', 'Close');?></button><button type="submit" id="btn_save_pf" class="btn btn-info" disabled><i class="fa fa-save"></i> Issue Proforma</button></div></form></div></div></div>
