<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function pfNum(v){v=parseFloat(v||0);return isNaN(v)?0:v;}function pfFmt(v){return pfNum(v).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}
function pfError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_proforma_process_failed', 'Proforma Invoice failed to process.');?>);$('.error_data_delete').fadeIn();}
function pfFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer:$('#filter_customer').val(),ref_type:$('#filter_ref_type').val(),status:$('#filter_status').val(),keyword:$('#filter_keyword').val()};}
function pfQuery(){return $.param(pfFilters());}
function setAmounts(r){$('#net_amount').val(r.net_amount);$('#tax_amount').val(r.tax_amount);$('#gross_amount').val(r.gross_amount);$('#net_preview').text(pfFmt(r.net_amount));$('#tax_preview').text(pfFmt(r.tax_amount));$('#gross_preview').text(pfFmt(r.gross_amount));$('#btn_save_pf').prop('disabled',!$('#reference_no').val());}
$(function(){if($.fn.datepicker){$('.pf-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer,#filter_ref_type,#filter_status,#reference_type,#sales_order_id,#quotation_id').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_proforma_invoice').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'112px',targets:1}],ajax:{url:'<?=base_admin();?>modul/proforma_invoice/proforma_invoice_data.php',type:'post',data:function(d){$.extend(d,pfFilters());},error:function(xhr){console.log(xhr.responseText);pfError(<?=sd_js('sales_proforma_load_failed', 'Proforma data failed to load.');?>);}}});
$('#btn_filter_pf').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#btn_reset_pf').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer,#filter_ref_type,#filter_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_pf').click(function(){window.location='<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=excel&'+pfQuery();});
function getNo(){$.getJSON('<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=get_no',function(r){$('#no_sales_invoice').val(r.no||'');});}
function toggleSource(){var t=$('#reference_type').val();$('.pf-ref').hide();$('.pf-ref-'+(t==='SO'?'so':'quotation')).show();$('#sales_order_id,#quotation_id').val('').trigger('change');$('#source_summary').hide();$('#reference_no').val('');setAmounts({net_amount:0,tax_amount:0,gross_amount:0});}
$('#btn_add_pf').click(function(){$('#form_pf')[0].reset();$('.error_data').hide();$('#invoice_date').val('<?=date('Y-m-d');?>');$('#proforma_valid_until').val('<?=date('Y-m-d',strtotime('+30 days'));?>');$('#reference_type').val('SO').trigger('change');getNo();toggleSource();$('#modal_pf_form').modal('show');});
$('#reference_type').change(toggleSource);
function loadSource(type,id){if(!id)return;$.getJSON('<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=get_source',{type:type,id:id},function(r){if(r.status==='error'){Swal.fire('Error',r.error_message,'error');return;}$('#bill_to').val(r.bill_to);$('#ship_to').val(r.ship_to);$('#reference_no').val(r.reference_no);$('#no_sales_order').val(r.no_sales_order);$('#nopo').val(r.nopo);$('#valuta').val(r.valuta);$('#tax').val(r.tax);$('#tax_label').val(r.tax==='1'?'PPN':'Non');$('#source_summary').html(r.html).show();setAmounts(r);});}
$('#sales_order_id').change(function(){loadSource('SO',$(this).val());});$('#quotation_id').change(function(){loadSource('QUOTATION',$(this).val());});
$('#form_pf').ajaxForm({dataType:'json',beforeSubmit:function(){$('#loadnya').show();},success:function(res){$('#loadnya').hide();var ok=false,msg='';$.each(res||[],function(_,r){if(r.status==='good')ok=true;if(r.status==='error')msg=r.error_message;});if(ok){$('#modal_pf_form').modal('hide');Swal.fire('Success','Proforma Invoice berhasil diterbitkan.','success');dt.draw(false);}else{$('.isi_warning').text(msg||<?=sd_js('sales_proforma_save_failed', 'Proforma failed to save.');?>);$('.error_data').fadeIn();}},error:function(xhr){$('#loadnya').hide();console.log(xhr.responseText);$('.isi_warning').text(<?=sd_js('sales_proforma_save_failed', 'Proforma failed to save.');?>);$('.error_data').fadeIn();}});
$(document).on('click','.btn-pf-detail',function(){$.post('<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=detail',{id:$(this).data('id')},function(html){$('#pf_detail_body').html(html);$('#modal_detail_pf').modal('show');}).fail(function(){pfError('Detail gagal dibuka.');});});
$(document).on('click','.btn-pf-cancel',function(){var id=$(this).data('id');Swal.fire({title:'Cancel Proforma?',input:'text',inputLabel:'Alasan cancel',inputPlaceholder:'Masukkan alasan',icon:'warning',showCancelButton:true,confirmButtonText:'Cancel Proforma',inputValidator:function(v){if(!v)return 'Alasan wajib diisi';}}).then(function(r){if(!r.isConfirmed)return;$.post('<?=base_admin();?>modul/proforma_invoice/proforma_invoice_action.php?act=cancel',{id:id,reason:r.value},function(res){var ok=false,msg='';$.each(res||[],function(_,x){if(x.status==='good')ok=true;if(x.status==='error')msg=x.error_message;});if(ok){Swal.fire('Success','Proforma berhasil dicancel.','success');dt.draw(false);}else Swal.fire('Error',msg||'Cancel gagal.','error');},'json');});});
});
</script>
